// 创建一个空字符串用于存储合并后的文本
let mergedText = '';

// 提取JSON数组中的特定字段并按格式输出
const jsonData = $input.all();

/**
 * 提取JSON数组中的特定字段并按格式输出
 * @param {Array} data - 包含文章信息的JSON数组
 * @returns {string} - 合并后的文本字符串
 */
function extractFields(data) {
  if (!Array.isArray(data) || data.length === 0) {
    return '';
  }

  return data.map(item => {
    const title = item.json.name || '';
    const summary = item.json.property_ai || '';
    const url = item.json.property_url || '';
    return `标题：${title}\n摘要：${summary}\n链接：${url}\n\n`;
  }).join('');
}

// 执行函数并将结果赋值给mergedText
mergedText = extractFields(jsonData);
return {
    mergedText: mergedText.trim() // 去除最后的多余换行
};

