// 创建一个空字符串用于存储合并后的文本
let mergedText = '';

// 提取JSON数组中的特定字段并按格式输出
const jsonData = $input.all();

/**
 * 提取JSON数组中的特定字段并按格式输出
 * @param {Array} data - 包含文章信息的JSON数组
 * @returns {string} - 合并后的文本字符串
 */
function extractFields(data) {
  if (!Array.isArray(data) || data.length === 0) {
    return '';
  }

  return data.map(item => {
    const title = item.json.title || '';
    const summary = item.json.summary || '';
    return `${title} 摘要：${summary}  `;
  }).join('');
}

// 执行函数并将结果赋值给mergedText
mergedText = extractFields(jsonData);
return {
    mergedText: mergedText.trim() // 去除最后的多余换行
};

// 直接去拿 Loop 节点最开始输入的原始数据
const originalData = $('Loop Over Items').all(); 

// 直接去拿 Notion 节点产生的所有结果
const notionResults = $('分隔').all();

// 手动合并它们
return originalData.map((item, index) => {
  return {
    json: {
      ...item.json,
      notion_info: notionResults[index]?.json || {}
    }
  };
});
